      }
      if (!dataValues.some((dv) => dv.dataElement === "rbFVBI2N6Ex")) {
        dataValues.push({
          dataElement: "rbFVBI2N6Ex",
          value: visitUuid,
        });
      }
      return {
        event,
        program,
        orgUnit,
        occurredAt: eventDate,
        programStage,
        dataValues,
        trackedEntity: tei.trackedEntity,
      };
    }
  );

  return state;
});

