    console.log(`Affected Option Sets: ${uniqueOptionSets}`);
    console.log(`Affected Data Elements: ${uniqueDataElements}`);
    console.log(`View Details: ${googleSheetUrl}`);
    console.log("━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━");
    console.log("");
  } else {
